+fn merge_distributed_remote_pane_states(
+    states: &mut Vec<PaneState>,
+    remote_records: Vec<frankenterm_core::storage::PaneRecord>,
+) {
+    let mut existing_pane_ids: HashSet<u64> = states.iter().map(|state| state.pane_id).collect();
